#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int vis[100010],match[100010];
bool dfs(int x,int t)
{
    for(int i:mp[x])
    {
        if(vis[i]==t)
        {
            continue;
        }
        vis[i]=t;
        if(match[i]==0||dfs(match[i],t))
        {
            match[i]=x;
            match[x]=i;
            return true;
        }
    }
    return false;
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y+n);
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=dfs(i,i);
    }
    for(int i=1;i<=n;i++)
    {
        if(match[i+n]==0)
        {
            int x=i;
            while(x!=-n)
            {
                printf("%d ",x);
                x=match[x]-n;
            }
            printf("\n");
        }
    }
    printf("%d",n-ans);
    return 0;
}
